'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useSelection } from '@/context/SelectionContext';
import styles from './book.module.css';
import { ArrowLeft, Video, Phone, CheckCircle } from 'lucide-react';

export default function BookingPage() {
    const { selectedCoach } = useSelection();
    const [step, setStep] = useState(1);
    const [sessionType, setSessionType] = useState<'VIDEO' | 'PHONE'>('VIDEO');
    const [selectedTime, setSelectedTime] = useState<string | null>(null);
    const router = useRouter();

    const times = ['09:00', '10:30', '13:00', '15:30', '17:00'];

    const handleConfirm = () => {
        setStep(3);
    };

    if (step === 3) {
        return (
            <div className={styles.container}>
                <div className={styles.successCard}>
                    <CheckCircle size={64} color="var(--color-success)" />
                    <h1>Bokad och klar!</h1>
                    <p>Du har bokat ett {sessionType === 'VIDEO' ? 'videosamtal' : 'telefonsamtal'} med {selectedCoach?.name || 'din coach'}.</p>
                    <div className={styles.details}>
                        <p><strong>Tid:</strong> Imorgon kl {selectedTime}</p>
                        <p><strong>Typ:</strong> {sessionType === 'VIDEO' ? 'Videosamtal' : 'Telefonsamtal'}</p>
                    </div>
                    <button onClick={() => router.push('/')} className={styles.primaryBtn}>Tillbaka till start</button>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.container}>
            <header className={styles.header}>
                <div className="container flex items-center gap-md">
                    <button onClick={() => router.back()} className={styles.backBtn}><ArrowLeft size={20} /></button>
                    <h1>Boka tid med {selectedCoach?.name || 'din coach'}</h1>
                </div>
            </header>

            <div className="container section-padding">
                <div className={styles.card}>
                    <section className={styles.section}>
                        <h3>1. Välj typ av samtal</h3>
                        <div className={styles.typeGrid}>
                            <button
                                onClick={() => setSessionType('VIDEO')}
                                className={`${styles.typeBtn} ${sessionType === 'VIDEO' ? styles.active : ''}`}
                            >
                                <Video size={24} />
                                <div>
                                    <p className={styles.typeTitle}>Videosamtal</p>
                                    <p className={styles.typeSub}>Via vår säkra länk</p>
                                </div>
                            </button>
                            <button
                                onClick={() => setSessionType('PHONE')}
                                className={`${styles.typeBtn} ${sessionType === 'PHONE' ? styles.active : ''}`}
                            >
                                <Phone size={24} />
                                <div>
                                    <p className={styles.typeTitle}>Telefonsamtal</p>
                                    <p className={styles.typeSub}>Coachen ringer upp dig</p>
                                </div>
                            </button>
                        </div>
                    </section>

                    <section className={styles.section}>
                        <h3>2. Välj en ledig tid</h3>
                        <div className={styles.timeGrid}>
                            {times.map(t => (
                                <button
                                    key={t}
                                    onClick={() => setSelectedTime(t)}
                                    className={`${styles.timeBtn} ${selectedTime === t ? styles.active : ''}`}
                                >
                                    {t}
                                </button>
                            ))}
                        </div>
                    </section>

                    <footer className={styles.footer}>
                        <button
                            disabled={!selectedTime}
                            onClick={handleConfirm}
                            className={styles.confirmBtn}
                        >
                            Bekräfta bokning
                        </button>
                    </footer>
                </div>
            </div>
        </div>
    );
}
